func:
// Khai báo tool động cho aigg-mcp. Thêm/bớt tool tại đây (đổi tức thì, không build lại MCP).
msg.payload = {
  tools: [
    { name: 'aigg_active_task', description: 'Tự xác định công việc đang làm từ git branch hiện tại (vd AIGG-123-...) và task đã giao cho AI.',
      inputSchema: { type: 'object', properties: {} } },
    { name: 'aigg_my_tasks', description: 'Liệt kê công việc đang giao cho tôi (theo token người gọi).',
      inputSchema: { type: 'object', properties: {} } },
    { name: 'aigg_assign_to_ai', description: 'Giao một công việc (work task) cho AI: tạo ai_task + trả X-Task-ID để gắn vào phiên.',
      inputSchema: { type: 'object', properties: {
        taskId: { type: 'number', description: 'ID công việc (tasks.id). Bỏ trống = tự lấy từ git branch.' },
        baselineHours: { type: 'number', description: 'Số giờ công ước tính (mốc ROI).' },
        endDate: { type: 'string', description: 'Hạn (YYYY-MM-DD), tùy chọn.' },
        budgetTokens: { type: 'number', description: 'Ngân sách token, tùy chọn.' },
        moreDesc: { type: 'string', description: 'Ngữ cảnh thêm cho AI, tùy chọn.' },
        title: { type: 'string', description: 'Tiêu đề tác vụ AI, tùy chọn.' }
      }, required: ['baselineHours'] } },
    { name: 'aigg_ai_assignment', description: 'Xem việc đã giao cho AI của một công việc (trạng thái, budget, hạn).',
      inputSchema: { type: 'object', properties: { taskId: { type: 'number' } } } },
    { name: 'aigg_report_usage', description: 'Báo cáo usage AI cho task đang làm. Gửi kèm promptText để hệ thống capture & đánh giá prompt (Prompt Management).',
      inputSchema: { type: 'object', properties: {
        taskId: { type: 'string' },
        promptText: { type: 'string', description: 'Nội dung prompt/ngữ cảnh đầu vào (chỉ lưu bản rút gọn + hash).' },
        completionText: { type: 'string', description: 'Nội dung phản hồi (tùy chọn, để ước lượng token).' },
        promptTokens: { type: 'number' }, completionTokens: { type: 'number' }, model: { type: 'string' }
      } } },
    { name: 'aigg_quota', description: 'Xem hạn ngạch token còn lại (DAILY/WEEKLY/MONTHLY/TASK) cho task hiện tại.',
      inputSchema: { type: 'object', properties: { taskId: { type: 'string' } } } }
  ]
};
return msg;

// Bộ não: nhận { tool, arguments, context } + Authorization (JWT) từ aigg-mcp, gọi Gateway.
const fetch = global.get('fetch');
const GATEWAY = (global.get('gatewayUrl') || 'http://localhost:3900').replace(/\/+$/, '');
const BRANCH_RE = new RegExp(global.get('branchTaskRegex') || '(?:^|[/_-])(?:AIGG-)?(\\d+)', 'i');
const auth = (msg.req && msg.req.headers && msg.req.headers.authorization) || '';
const body = msg.payload || {};
const tool = body.tool;
const args = body.arguments || {};
const context = body.context || {};
const H = Object.assign({ 'Content-Type': 'application/json' }, auth ? { Authorization: auth } : {});

const call = async (method, path, payload) => {
  const r = await fetch(GATEWAY + path, { method, headers: H, body: payload ? JSON.stringify(payload) : undefined });
  const t = await r.text();
  let d; try { d = t ? JSON.parse(t) : null; } catch (e) { d = t; }
  if (!r.ok) throw new Error((d && d.message) || ('HTTP ' + r.status));
  return d;
};
const me = async () => call('GET', '/v1/auth/me');
const branchWorkTaskId = () => { const b = (context.gitBranch || ''); const m = b.match(BRANCH_RE); return m ? Number(m[1]) : null; };
const resolveActive = async () => {
  const wid = branchWorkTaskId();
  if (!wid) return { branch: context.gitBranch || null, note: 'Branch không khớp mẫu task (vd AIGG-123-...).' };
  let task = null, assign = null;
  try { task = await call('GET', '/v1/work/tasks/' + wid); } catch (e) {}
  try { assign = await call('GET', '/v1/work/tasks/' + wid + '/ai-assignment'); } catch (e) {}
  return { branch: context.gitBranch, workTaskId: wid, title: task && task.title, aiTaskId: assign && assign.aiTaskId, aiStatus: assign && assign.status, note: assign ? 'Dùng aiTaskId làm X-Task-ID.' : 'Công việc chưa giao cho AI (gọi aigg_assign_to_ai).' };
};
const effectiveTaskId = async () => {
  if (args.taskId) return args.taskId;
  if (context.activeTaskId) return context.activeTaskId;
  const a = await resolveActive();
  return a.aiTaskId || null;
};

try {
  let result;
  switch (tool) {
    case 'aigg_active_task':
      result = await resolveActive();
      break;
    case 'aigg_my_tasks': {
      const u = await me();
      const res = await call('GET', '/v1/work/tasks?assignedToUserId=' + u.id + '&pageSize=50');
      result = { user: u.fullName, count: res.total, tasks: res.rows.map((t) => ({ id: t.id, title: t.title, status: t.status, priority: t.priority, project: t.project && t.project.title, category: t.category && t.category.title, due: t.dueDate })) };
      break;
    }
    case 'aigg_assign_to_ai': {
      const wid = args.taskId || branchWorkTaskId();
      if (!wid) throw new Error('Thiếu taskId và git branch không chứa mã task.');
      const r = await call('POST', '/v1/work/tasks/' + wid + '/assign-ai', { baselineHours: Number(args.baselineHours) || 1, endDate: args.endDate, budgetTokens: args.budgetTokens, moreDesc: args.moreDesc, title: args.title });
      result = { ok: true, aiTaskId: r.id, taskId: wid, message: 'Đã giao việc cho AI. X-Task-ID = ' + r.id };
      break;
    }
    case 'aigg_ai_assignment': {
      const wid = args.taskId || branchWorkTaskId();
      if (!wid) throw new Error('Thiếu taskId và git branch không chứa mã task.');
      result = (await call('GET', '/v1/work/tasks/' + wid + '/ai-assignment')) || { note: 'Chưa giao cho AI.' };
      break;
    }
    case 'aigg_report_usage': {
      const u = await me();
      const taskId = await effectiveTaskId();
      if (!taskId) throw new Error('Không xác định được task (taskId/activeTaskId/branch).');
      result = await call('POST', '/v1/usage/ingest', {
        taskId: taskId, requesterId: u.email, model: args.model || 'claude-3-5-sonnet',
        promptText: args.promptText, completionText: args.completionText,
        promptTokens: args.promptTokens != null ? Number(args.promptTokens) : undefined,
        completionTokens: args.completionTokens != null ? Number(args.completionTokens) : undefined,
        captureMode: 'API', projectId: context.projectId || undefined, conversationId: context.conversationId || undefined
      });
      break;
    }
    case 'aigg_quota': {
      const taskId = (await effectiveTaskId()) || 'N/A';
      result = await call('GET', '/v1/quotas/me?taskId=' + encodeURIComponent(taskId));
      break;
    }
    default:
      throw new Error('Tool chưa hỗ trợ: ' + tool);
  }
  msg.payload = result;
} catch (e) {
  msg.statusCode = 400;
  msg.payload = { error: e.message };
}
return msg;

const ev = msg.payload || {};
node.warn('[AIGG noti] ' + (ev.event || '?') + ' :: ' + JSON.stringify(ev.payload || {}));
msg.payload = { received: true, event: ev.event };
return msg;
